window.__QUIZ_DATA__=[{"id":"theory>Geography>2015>Theory 1>1>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"List four commodities exported from your country to any one European country.","images":[],"marking_scheme":"- Crude oil  - Timber   - Hide and skin   - Rubber","marks":"8","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>1>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline four reasons for the low volume of trade among West African countries","images":[],"marking_scheme":"- Poor qualities of goods for sale   - Bad government policy   - Colonial ties and relations   - Taste for foreign goods","marks":"7","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>1>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Suggest four ways of improving trade among West African countries","images":[],"marking_scheme":"- Good governance   - Improvement in technology   - Introduction of common currency   - Wages should be increased in order to stimulate good yield.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>2>a>i","subject":"Geography","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Define death rate","images":[],"marking_scheme":"Death rate can be defined as the number of death in a year per 1000 people of a given population.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2015>Theory 1>2>a>ii","subject":"Geography","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Define population explosion.","images":[],"marking_scheme":"Population Explosion is defined as the rapid increase in the population of a place over a short period of time.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2015>Theory 1>2>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain five factors that influence death rate in Tropical Africa.","images":[],"marking_scheme":"- Natural disaster   - Family planning   - Improve living standard   - Improved food production   - Education and illiteracy","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>2>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline three effects of a growing population in Tropical Africa.","images":[],"marking_scheme":"- Social unrest   - High demand for goods   - Poor waste management","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>3>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five factors that should be considered in the location of an industry","images":[],"marking_scheme":"- Availability of capital   - Political stability   - Nearness to source of raw materials   - Availability of water supply   - Adequate power supply","marks":"10","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>3>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"State five benefits of industrialization to a country.","images":[],"marking_scheme":"- It provides various goods and services for consumer   - It provides income to operators   - Provision of goods   - It curbs rural-urban migration   - Diversification of economy","marks":"10","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>4>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria. On the map, show and name: (i) the position of Tropical Maritime air mass (S.W. Winds) in July;   (ii) the position of Inter Tropical Convergence Zone (I. T. C. Z) in July; (iii) the relative position of Tropical Continental air mass (N. E. Winds) in July; (iv) three towns located in 4(a)(i) above.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"15","difficulty":"3"},{"id":"theory>Geography>2015>Theory 1>4>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : WEATHER AND CLIMATE","question":"State four characteristics of the wet season in Nigeria.","images":[],"marking_scheme":"- A high temperature of about 27oC to 33oC is recorded   - Diurnal range of temperature increases Northwards (2o - 11oC)  - Rainfall amount decreases from South to the North  - Heavy rainfall is recorded in the North in July","marks":"3","difficulty":"2"},{"id":"theory>Geography>2015>Theory 1>4>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"List two cash crops grown during the wet season in Nigeria.","images":[],"marking_scheme":"- Maize   - Cocoa","marks":"2","difficulty":"1"},{"id":"theory>Geography>2015>Theory 1>5>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline five problems of agricultural development in Nigeria","images":[],"marking_scheme":"- High cost of Agricultural inputs   - Farming practices are not mechanized   - Infestion of pests like locusts, grasshoppers, rodents, etc.   - Inadequate processing facilities   - Rural-urban migration","marks":"10","difficulty":"3"},{"id":"theory>Geography>2015>Theory 1>5>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Suggest solutions to the problems outlined in 5(a) above","images":[],"marking_scheme":"- Loan facilities and Incentives should be given to farmers   - Mechanized agriculture should be practiced   - Pesticides should be applied on a regular basis in the farms  - Processing plants should also be developed in order to prevent rural-urban migration.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2015>Theory 1>6>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map, show and name one area with:   (i) Mangrove swamp vegetation; (ii) Rain forest vegetation; (iii) Guinea savanna vegetation; (iv) Sudan savanna vegetation","images":["data:image/png;base64,"],"marking_scheme":"","marks":"15","difficulty":"3"},{"id":"theory>Geography>2015>Theory 1>6>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : VEGETATION","question":"Name three types of trees found in the forest zone of Nigeria.","images":[],"marking_scheme":"- African walnut   - Obeche   - Mahogany","marks":"3","difficulty":"1"},{"id":"theory>Geography>2015>Theory 1>6>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Explain four contributions of forest vegetation to the economic development of Nigeria.","images":[],"marking_scheme":"- Provision of employment/job opportunities for lumbermen, hunters, etc.   - Provision of food i.e games   - Provision of tourist attractions   - Provision of herbs for medicinal uses","marks":"2","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>1>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the questions that follow.    Reduce the mapped area to a third of its original size and state the scale of the new outline","images":[],"marking_scheme":"Old length = 37.5cm   Old breadth = 36.9cm   Old scale = 1:50,000   Newlength=37.53cm=12.5cm  Newbreadth=36.93cm=12.3cm    New scale = 1:150,000","marks":"5","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>1>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"In your new outline, insert and name:   (i) River Pra and indicate its direction of flow with an arrow;   (ii) The class 3 road running from PRASO settlement to AKIM OFOASE settlement;   (iii) KOTOKUOM settlement","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>1>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe three drainage characteristics of River Pra.","images":[],"marking_scheme":"- It has many confluences   - It is about 10 - 100 ft wide   - Its tributary is River Anum   - It has a dendritic drainage pattern   - It flows through a narrow valley, an undulating plain and from the north to the South.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>1>d","subject":"Geography","year":"2015","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Using the evidence from the map, state three functions of AKIM OFOASE settlement","images":[],"marking_scheme":"- Commercial function as indicated by the presence of market   - Educational function shown by the presence of school   - Security function evidence by the presence of police station.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>2>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The data below shows the number of farmers who cultivated the underlisted crops in Ajok Region from 2005 to 2007.  YEARS CASSAVA MAIZE RICE YAM2005 50 60 45 802006 40 62 55 48 2007 48 58 70 35    Draw a divided bar graph to represent the data.","images":["data:image/png;base64,"],"marking_scheme":"Year Cassava Maize Rice Yam Total2005 50 60 45 80 2352006 40 62 55 48 205 2007 48 58 70 35 211  138 180 170 163     A Divided Bar Chart showing the number of farmers who cultivated yam, Rice, Maize and Cassava in Ajok from 2005 - 2007.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>2>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The data below shows the number of farmers who cultivated the underlisted crops in Ajok Region from 2005 to 2007.  YEARS CASSAVA MAIZE RICE YAM2005 50 60 45 802006 40 62 55 48 2007 48 58 70 35  Calculate the number of farmers who cultivated rice from 2005 to 2007.","images":[],"marking_scheme":"Number of rice farmers from 2005 - 2007 =   45 + 55 + 70 = 170 farmers.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>2>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The data below shows the number of farmers who cultivated the underlisted crops in Ajok Region from 2005 to 2007.  YEARS CASSAVA MAIZE RICE YAM2005 50 60 45 802006 40 62 55 48 2007 48 58 70 35  What is the major difference between simple bar graph and the component/divided bar graph?","images":[],"marking_scheme":"Simple bar graph is a chart that shows only one component bar graph shows more than one (1) component in a bar.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>3>a>i","subject":"Geography","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Explain the following terms:    rotation of the earth","images":[],"marking_scheme":"Rotation of the earth can be defined as movement of the earth on its axis from west to east in an anti-clockwise direction. The rotation of the earth occurs every 24hours at a speed of about 4.7kms-1 at latitude 60o.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>3>a>ii","subject":"Geography","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Explain the following terms:revolution of the earth;","images":[],"marking_scheme":"This is movement of the earth around the sun on its orbit (elliptical). This takes about 365 1/4 days to be completed. The earth, when revolving makes an angle 66 1/2 o to the ecliptic plane.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>3>a>iii","subject":"Geography","year":"2015","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Explain the following terms:equinox","images":[],"marking_scheme":"This is an occurrence of equality in the day and night period all over the globe which occurs twice yearly because the mid-day sun is directly overhead the equator. It occurs in the Spring and Autumn-on March 21st in the Northern hemisphere and September 23rd in the Southern hemisphere.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>3>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Outline three effects of the revolution of the earth.","images":[],"marking_scheme":"- This brings about changes in seasons   - It results into varying durations of day and night   - It marks years (their beginning and their end)","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>4>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"List three landforms found in the upper course of a river valley.","images":[],"marking_scheme":"- V-shaped valley   - Rapids   - Plunge pool","marks":"10","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>4>b>i","subject":"Geography","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe the characteristics of Ox-bow Lake","images":[],"marking_scheme":"- It is a land form in the lower course of a river   - Erosion occurs on the concave bank   - Deposition occurs on its convex bank","marks":"5","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>4>b>ii","subject":"Geography","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of a diagram describe the mode of formation of ox-bow lake.","images":[],"marking_scheme":"It is formed in the lower course of a river due to pronounced meanders i.e After erosion occurs on the concave bank and deposition occurs on the convex bank, the neck becomes very narrow and river breaks through the neck during floods leading to the deposition of sediments at the loop entrance. This then results in a cut off lake known as the 'Ox-bow lake.'","marks":"5","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>5>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"List any three types of mountain","images":[],"marking_scheme":"- Volcanic mountains   - Residual mountains   - Block mountains","marks":"8","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>5>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"In what four ways are mountains important to man?","images":[],"marking_scheme":"- For tourism   - For cultivation of some crops like Coffee and Tea  - As a source of minerals e.g Gold   - As wind breakers","marks":"7","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>5>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Outline two problems caused by mountains","images":[],"marking_scheme":"- They encourage landslides   - They also pose a danger as volcanic eruptions occur.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>6>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Define climate","images":[],"marking_scheme":"Climate can be defined as the average condition of a place over a long period of time usually between 30 - 35 years","marks":"8","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>6>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Describe the three climatic belts recognized by the Greek system of classification.","images":[],"marking_scheme":"- Temperature Zone: This is found in the middle of the torrid and frigid Zones. It has moderate temperatures.   - Torrid zone: This zone is found within the tropics. It has all year round hot temperature.   - Frigid Zone: It is found between the polar regions i.e the Arctic and Antartic Regions. Normally, this is a cold zone with lots of ice caps in much of the year and has a low temperature through out the year.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>6>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Outline three reasons why koppen's system of climatic classification is the most widely accepted.","images":[],"marking_scheme":"- It is objective   - It makes use of more than one parameter for classification   - It is very simple to comprehend","marks":"5","difficulty":"2"},{"id":"theory>Geography>2015>Theory 2>7>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"What are environmental hazards?","images":[],"marking_scheme":"Environmental Hazards are disasters or dangers caused by nature or are man-made which pose serious threats to the lives and properties of people in that environment.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>7>b","subject":"Geography","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"List three examples of environmental hazards","images":[],"marking_scheme":"- Earthquakes   - Flooding   - Tsunamis","marks":"7","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>7>c","subject":"Geography","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Explain five ways of preventing desert encroachment.","images":[],"marking_scheme":"- Rotational cropping and grazing   - Afforestation   - Cover cropping   - Legislations against bush burning   - Controlled lumbering","marks":"5","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>8>a","subject":"Geography","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"List three features of coastal erosion","images":[],"marking_scheme":"- Blowholes   - Arch   - Geo","marks":"8","difficulty":"1"},{"id":"theory>Geography>2015>Theory 2>8>b>i","subject":"Geography","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of diagram, describe the characteristics and mode of formation of a beach.    - Characteristic of beach","images":[],"marking_scheme":"- Presence of sand, gravel, etc  - Found majorly in lowlying coasts  - Possession of concave profile   - Coastal land form","marks":"7","difficulty":"3"},{"id":"theory>Geography>2015>Theory 2>8>b>ii","subject":"Geography","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of diagram, describe the characteristics and mode of formation of a beach.formation of a beach","images":[],"marking_scheme":"They are formed at coastal areas by riber deposition i.e the swash and backwash of low tides. Sand and gravel washed from land are wave-carried and deposited on the shore. Coarse and fine sand/gravel are deposited at the landward and Seaward sides respectively.","marks":"5","difficulty":"3"}];